#!/usr/bin/env bash
# build-an-outbound-prospecting-se.sh — Build an outbound prospecting sequence from 0（从 0 建立一个外呼开发序列） SOP walkthrough for B2B 大客户销售.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="B2B 大客户销售"
WORKFLOW="Build an outbound prospecting sequence from 0（从 0 建立一个外呼开发序列）"

usage() {
  cat <<EOF
build-an-outbound-prospecting-se.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./build-an-outbound-prospecting-se.sh             # interactive
  ./build-an-outbound-prospecting-se.sh --dry-run
  ./build-an-outbound-prospecting-se.sh --json
  ./build-an-outbound-prospecting-se.sh --explain
  ./build-an-outbound-prospecting-se.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Build an outbound prospecting sequence from 0（从 0 建立一个外呼开发序列）" 工作流。

一句话: Turn an empty territory into booked discovery calls — define ICP, build a list, run a multichannel cadence, and stay legal across geographies. The most **AI-disrupted and compliance-sensitive** workflow in the industry. (evidence: [T03-S009, T03-S010, T03-S012])

入门 SOP 共 5 步, 失败模式自检 4 项。

相关心智模型:
  • 问 ⇄ 教 ⇄ 筛:三派第一性张力,资深人按层混用: 复杂销售的方法论分三派——诊断式提问(SPIN/Gap:「客户有答案,问到痛点不可否认为止」)⇄ 挑战式教学(Challenger:「客户对自己问题的认知是错的,用商业洞见 reframe」)⇄ 资格
  • 头号对手是「不决策」,不是竞品: 预测内丢单的最大去向不是输给对手,而是客户「什么都不做」——维持现状;且一旦购买意向形成,买方更怕「搞砸」(FOMU)而非「错过」(FOMO),所以晚期停滞要按「犹豫」处理(去风险),不是按「异议」处

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**Define the ICP + personas** — firmographic fit (ICP, account-level) *and* the buying-committee personas within it (person-level). (evidence: [T03-S010])"
  "**Build the list + enrich** — pull ICP-matched accounts/contacts (prospecting-data tools) with verified emails/phones. (evidence: [T03-S010])"
  "**Design the multichannel cadence** — ~10-14 touches over 30 days, phased into problem-themes: Theme 1 (days 1-7: opener + bubble-ups), Theme 2 (days 8-14: new angle + qualification), Breakup (days 15-30: yes/no). Phase out LinkedIn by theme 2 and cold calls by theme 3 to redirect effort to fresher prospects; LinkedIn exists to *lift email replies*, not to close. (evidence: [T03-S009])"
  "**Write interest-based, problem-led copy** — lead with context/problem, use low-pressure \"any thoughts?\" CTAs instead of an immediate meeting ask (raises reply rate, lowers spam flags). (evidence: [T03-S009, T03-S011])"
  "**Compliance gate by geography** — CAN-SPAM (US: no B2B exemption, working opt-out in 10 days, real address); CASL (Canada: opt-in, up to \$10M/violation); PECR + UK GDPR (corporate-subscriber exception, soft opt-in only for existing customers); GDPR (EU: legitimate-interest + documented LIA); TCPA for calls/SMS. (evidence: [T03-S012, T03-S013])"
)
declare -a FAILURE_MODES=(
  "**Run a fully-autonomous AI SDR at vendor-recommended volume → deliverability collapses, domain burned**: everyone pointing the same AI at the same playbook saturated inboxes in 2025. Avoid: run hybrid (AI volume + human nuance), warm domains, keep lists clean. (evidence: [T03-S009])"
  "**Assume \"B2B cold email is exempt from spam law\"**: CAN-SPAM has *no* B2B exemption; CASL is opt-in; CCPA now covers work-contact data. Avoid: build a geo-routed compliance gate before the first send. (evidence: [T03-S012])"
  "**Too few touches / single channel → never connect**: it takes ~9-12 touches across channels to reach a prospect; one email converts near zero. Avoid: 10-14 touches over 30 days, phased multichannel. (evidence: [T03-S010, T03-S009])"
  "**Immediate meeting-ask CTA → ignored + spam-flagged**: cold \"book a demo\" requests tank reply rates. Avoid: interest-based \"any thoughts?\" CTAs first; escalate only on engagement. (evidence: [T03-S009])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "build-an-outbound-prospecting-se-walkthrough"
fi
